import React from 'react';
import type { BankStatementDryRunResult, BankStatementDryRunRow } from '../../../../../services/kt/bankStatementImportModels';

interface Step2DryRunProps {
  dryRunResult: BankStatementDryRunResult;
  onNext: () => void;
  onBack: () => void;
}

const STATUS_LABEL: Record<string, { text: string; className: string }> = {
  ok: { text: 'Sẵn sàng', className: 'statusOk' },
  missing_customer: { text: 'Thiếu KH', className: 'statusMissing' },
  error: { text: 'Lỗi', className: 'statusError' },
};

const Step2DryRun: React.FC<Step2DryRunProps> = ({ dryRunResult, onNext, onBack }) => {
  const hasMissingCustomers = dryRunResult.missingCustomerCount > 0;

  return (
    <div style={{ maxWidth: 960, margin: '0 auto', padding: 24 }}>
      <h2 style={{ fontSize: 20, fontWeight: 600, margin: '0 0 8px 0' }}>
        Bước 2: Kết quả phân tích
      </h2>

      {/* Summary cards */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 24 }}>
        <div style={{ flex: 1, background: '#f0fdf4', padding: 16, borderRadius: 8, border: '1px solid #bbf7d0' }}>
          <div style={{ fontSize: 24, fontWeight: 700, color: '#16a34a' }}>{dryRunResult.readyCount}</div>
          <div style={{ fontSize: 13, color: '#15803d' }}>Sẵn sàng</div>
        </div>
        <div style={{ flex: 1, background: '#fffbeb', padding: 16, borderRadius: 8, border: '1px solid #fde68a' }}>
          <div style={{ fontSize: 24, fontWeight: 700, color: '#d97706' }}>{dryRunResult.missingCustomerCount}</div>
          <div style={{ fontSize: 13, color: '#b45309' }}>Thiếu khách hàng</div>
        </div>
        <div style={{ flex: 1, background: '#fef2f2', padding: 16, borderRadius: 8, border: '1px solid #fecaca' }}>
          <div style={{ fontSize: 24, fontWeight: 700, color: '#dc2626' }}>{dryRunResult.errorCount}</div>
          <div style={{ fontSize: 13, color: '#b91c1c' }}>Lỗi</div>
        </div>
      </div>

      {/* Rows table */}
      <div style={{ border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
          <thead>
            <tr style={{ background: '#f9fafb', borderBottom: '1px solid #e5e7eb' }}>
              <th style={thStyle}>#</th>
              <th style={thStyle}>Loại</th>
              <th style={thStyle}>Mã GD</th>
              <th style={thStyle}>Số tiền</th>
              <th style={thStyle}>Đối tượng</th>
              <th style={thStyle}>Nội dung</th>
              <th style={thStyle}>Trạng thái</th>
            </tr>
          </thead>
          <tbody>
            {dryRunResult.rows.map((row) => (
              <tr key={row.rowIndex} style={{ borderBottom: '1px solid #f3f4f6' }}>
                <td style={tdStyle}>{row.rowIndex + 1}</td>
                <td style={tdStyle}>{row.voucherType}</td>
                <td style={tdStyle}>{row.description?.slice(0, 20)}</td>
                <td style={{ ...tdStyle, textAlign: 'right' }}>
                  {row.amount?.toLocaleString('vi-VN')}
                </td>
                <td style={tdStyle}>
                  {row.matchedCustomerName || (
                    row.status === 'missing_customer'
                      ? <span style={{ color: '#d97706' }}>⛔ Chưa có</span>
                      : ''
                  )}
                </td>
                <td style={tdStyle}>{row.description?.slice(0, 30)}</td>
                <td style={tdStyle}>
                  <span style={{
                    display: 'inline-block',
                    padding: '2px 8px',
                    borderRadius: 4,
                    fontSize: 12,
                    fontWeight: 500,
                    background: row.status === 'ok' ? '#dcfce7' : row.status === 'missing_customer' ? '#fef3c7' : '#fee2e2',
                    color: row.status === 'ok' ? '#16a34a' : row.status === 'missing_customer' ? '#d97706' : '#dc2626',
                  }}>
                    {STATUS_LABEL[row.status]?.text || row.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {hasMissingCustomers && (
        <div style={{ marginTop: 16, padding: 12, background: '#fffbeb', borderRadius: 8, border: '1px solid #fde68a' }}>
          <p style={{ margin: 0, fontSize: 13, color: '#92400e' }}>
            Có {dryRunResult.missingCustomerCount} dòng chưa xác định được khách hàng.
            Bước tiếp theo sẽ giúp bạn tìm hoặc tạo mới khách hàng cho các dòng này.
          </p>
        </div>
      )}

      <div style={{ marginTop: 24, display: 'flex', justifyContent: 'space-between' }}>
        <button onClick={onBack} style={secondaryBtnStyle}>
          ← Quay lại
        </button>
        <button onClick={onNext} style={primaryBtnStyle}>
          Tiếp theo: Xử lý khách hàng →
        </button>
      </div>
    </div>
  );
};

const thStyle: React.CSSProperties = {
  padding: '8px 12px',
  textAlign: 'left',
  fontWeight: 600,
  fontSize: 12,
  color: '#6b7280',
  whiteSpace: 'nowrap',
};

const tdStyle: React.CSSProperties = {
  padding: '8px 12px',
  color: '#374151',
};

const primaryBtnStyle: React.CSSProperties = {
  background: '#6366f1',
  color: '#fff',
  border: 'none',
  padding: '10px 24px',
  borderRadius: 8,
  fontSize: 14,
  fontWeight: 500,
  cursor: 'pointer',
};

const secondaryBtnStyle: React.CSSProperties = {
  background: '#fff',
  color: '#374151',
  border: '1px solid #d1d5db',
  padding: '10px 24px',
  borderRadius: 8,
  fontSize: 14,
  cursor: 'pointer',
};

export default Step2DryRun;
